#include <bits/stdc++.h>
using namespace std;

const int N=60010,M=6*N,INF=1e8;

int n,m,S,T,d[N],now[N],sum,q[N],hh,tt;
int head[N],ver[M],nxt[M],edge[M],tot=1;

void add(int x,int y,int z){
    ver[++tot]=y,edge[tot]=z,nxt[tot]=head[x],head[x]=tot;
    ver[++tot]=x,edge[tot]=0,nxt[tot]=head[y],head[y]=tot;
}

bool bfs(){
    memset(d,0,sizeof(d));
    d[S]=1,now[S]=head[S];
    q[hh=tt=1]=S;
    while(hh<=tt){
        int x=q[hh];
        hh++;
        for(int i=head[x],y;i;i=nxt[i])
            if(edge[i] && !d[y=ver[i]]){
                d[y]=d[x]+1,now[y]=head[y];
                if(y==T)
                    return true;
                q[++tt]=y;
            }
    }
    return false;
}

int Dinic(int x,int flow){
    if(x==T)
        return flow;
    int res=0;
    for(int i=now[x],y;i && res<flow;i=nxt[i]){
        now[x]=i,y=ver[i];
        if(edge[i] && d[x]+1==d[y]){
            int tmp=Dinic(y,min(edge[i],flow-res));
            if(!tmp) d[y]=0;
            edge[i]-=tmp,edge[i^1]+=tmp;
            res+=tmp;
        }
    }
    return res;
}

int main(){
    scanf("%d%d",&n,&m);
    S=n+m+1,T=n+m+2;
    for(int i=1,p;i<=n;i++){
        scanf("%d",&p);
        add(m+i,T,p);
    }
    for(int i=1,a,b,c;i<=m;i++){
        scanf("%d%d%d",&a,&b,&c);
        add(i,m+a,INF);
        add(i,m+b,INF);
        add(S,i,c);
        sum+=c;
    }
    int flow;
    while(bfs())
        while(flow=Dinic(S,INF)) sum-=flow;
    printf("%d",sum);
    return 0;
}
